const var Synth1AHDSREnvelope = Synth.getModulator("AHDSR Envelope1");

inline function playTimedNote(ch, noteNb, noteVel)
{
	local time = Synth1AHDSREnvelope.getAttribute(2) + Synth1AHDSREnvelope.getAttribute(4) + Synth1AHDSREnvelope.getAttribute(5);
	local samples = Engine.getSamplesForMilliSeconds(time);
	local noteID = Synth.addNoteOn(ch, noteNb, noteVel, 0);
	Synth.noteOffDelayedByEventId(noteID, samples);
}

